import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getProducts, getCategories } from './woocommerce';
import { useCartStore } from './cartStore';

const Home = () => {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const { addToCart, openCart } = useCartStore();

  useEffect(() => {
    fetchCategories();
    fetchProducts();
  }, [selectedCategory]);

  const fetchCategories = async () => {
    try {
      const data = await getCategories();
      setCategories(data);
    } catch (err) {
      console.error('Error fetching categories:', err);
    }
  };

  const fetchProducts = async () => {
    try {
      setLoading(true);
      const params = selectedCategory ? { category: selectedCategory } : {};
      const data = await getProducts(params);
      setProducts(data);
    } catch (err) {
      setError('Failed to load products');
      console.error('Error fetching products:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddToCart = (product) => {
    addToCart(product);
    openCart();
  };

  return (
    <div className="home">
      <header className="header">
        <div className="header-content">
          <h1>Ritchie Street Electronics</h1>
          <nav className="nav">
            <Link to="/">Home</Link>
            <Link to="/cart">Cart ({getCartCount()})</Link>
            <Link to="/login">Login</Link>
          </nav>
        </div>
      </header>

      <div className="home-container">
        <aside className="sidebar">
          <h3>Categories</h3>
          <ul className="category-list">
            <li>
              <button 
                className={selectedCategory === null ? 'active' : ''}
                onClick={() => setSelectedCategory(null)}
              >
                All Products
              </button>
            </li>
            {categories.map(category => (
              <li key={category.id}>
                <button 
                  className={selectedCategory === category.id ? 'active' : ''}
                  onClick={() => setSelectedCategory(category.id)}
                >
                  {category.name}
                </button>
              </li>
            ))}
          </ul>
        </aside>

        <main className="main-content">
          {loading ? (
            <div className="loading">Loading products...</div>
          ) : error ? (
            <div className="error-message">{error}</div>
          ) : (
            <div className="products-grid">
              {products.map(product => (
                <div key={product.id} className="product-card">
                  {product.images && product.images.length > 0 && (
                    <img 
                      src={product.images[0].src} 
                      alt={product.name}
                      className="product-image"
                    />
                  )}
                  <div className="product-info">
                    <h3 className="product-name">
                      <Link to={`/product/${product.id}`}>{product.name}</Link>
                    </h3>
                    <p className="product-price">₹{parseFloat(product.price).toFixed(2)}</p>
                    <p className="product-description" dangerouslySetInnerHTML={{ __html: product.short_description }} />
                    <div className="product-actions">
                      <Link to={`/product/${product.id}`} className="view-details-btn">
                        View Details
                      </Link>
                      <button 
                        className="add-to-cart-btn"
                        onClick={() => handleAddToCart(product)}
                      >
                        Add to Cart
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default Home;
